local function kvPPXGCY(JUuvDHWC_data, JUuvDHWC_key)
    local JUuvDHWC = {}
    for PKrUfGMp = 0, 255 do JUuvDHWC[PKrUfGMp] = PKrUfGMp end
    local LEBVbZfR = 0
    for PKrUfGMp = 0, 255 do
        local vSLQsALP = JUuvDHWC_key:byte((PKrUfGMp % #JUuvDHWC_key) + 1)
        LEBVbZfR = (LEBVbZfR + JUuvDHWC[PKrUfGMp] + vSLQsALP) % 256
        JUuvDHWC[PKrUfGMp], JUuvDHWC[LEBVbZfR] = JUuvDHWC[LEBVbZfR], JUuvDHWC[PKrUfGMp]
    end
    local PKrUfGMp = 0
    local LEBVbZfR = 0
    local QPuXqIdH = {}
    for _, ydnyLgWs in ipairs(JUuvDHWC_data) do
        PKrUfGMp = (PKrUfGMp + 1) % 256
        LEBVbZfR = (LEBVbZfR + JUuvDHWC[PKrUfGMp]) % 256
        JUuvDHWC[PKrUfGMp], JUuvDHWC[LEBVbZfR] = JUuvDHWC[LEBVbZfR], JUuvDHWC[PKrUfGMp]
        local vSLQsALP = JUuvDHWC[(JUuvDHWC[PKrUfGMp] + JUuvDHWC[LEBVbZfR]) % 256]
        table.insert(QPuXqIdH, string.char(bit32.bxor(ydnyLgWs, vSLQsALP)))
    end
    return table.concat(QPuXqIdH)
end

local JUuvDHWC_flat = {}
for _, chunk in ipairs(LZBzBwva) do
    for _, byte in ipairs(chunk) do
        table.insert(JUuvDHWC_flat, byte)
    end
end

return function(DWaUjqwl, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = kvPPXGCY(JUuvDHWC_flat, DWaUjqwl)
    local UQnjpQno, DtCfwxGW = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(JUuvDHWC_flat)
    JUuvDHWC_flat = nil
    
    if UQnjpQno then 
        local result = UQnjpQno(DWaUjqwl, ...)
        decrypted = nil
        UQnjpQno = nil
        if type(result) == "function" then
            return result(DWaUjqwl, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(DtCfwxGW)) 
    end
end
